import{_ as a,c as r,o as t,a1 as i}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"流式中断: 0 Token 排查 | Antigravity-Manager","description":"学习 Antigravity Tools 流式中断、0 Token 与签名失效的排查路径。确认 /v1/messages 或 Gemini 流式调用，读懂 peek 预读与退避重试，结合 Proxy Monitor 和日志快速定位原因并判断是否需要轮换账号。","frontmatter":{"title":"流式中断: 0 Token 排查 | Antigravity-Manager","sidebarTitle":"自愈还是手动介入","subtitle":"流式中断/0 Token/签名失效：自愈机制与排查路径","description":"学习 Antigravity Tools 流式中断、0 Token 与签名失效的排查路径。确认 /v1/messages 或 Gemini 流式调用，读懂 peek 预读与退避重试，结合 Proxy Monitor 和日志快速定位原因并判断是否需要轮换账号。","tags":["faq","streaming","troubleshooting","retry"],"prerequisite":["start-getting-started","start-first-run-data","advanced-monitoring","advanced-scheduling"],"order":5},"headers":[],"relativePath":"zh/lbjlaq/Antigravity-Manager/faq/streaming-0token/index.md","filePath":"zh/lbjlaq/Antigravity-Manager/faq/streaming-0token/index.md"}'),o={name:"zh/lbjlaq/Antigravity-Manager/faq/streaming-0token/index.md"};function s(d,e,l,n,c,h){return t(),r("div",null,[...e[0]||(e[0]=[i('<h1 id="流式中断-0-token-签名失效-自愈机制与排查路径" tabindex="-1">流式中断/0 Token/签名失效：自愈机制与排查路径 <a class="header-anchor" href="#流式中断-0-token-签名失效-自愈机制与排查路径" aria-label="Permalink to &quot;流式中断/0 Token/签名失效：自愈机制与排查路径&quot;">​</a></h1><p>在 Antigravity Tools 里调用 <code>/v1/messages</code>（Anthropic 兼容）或 Gemini 原生流式接口时，如果你遇到“流式输出中断”“200 OK 但 0 Token”“Invalid <code>signature</code>”这类问题，本课给你一条从 UI 到日志的排查路径。</p><h2 id="学完你能做什么" tabindex="-1">学完你能做什么 <a class="header-anchor" href="#学完你能做什么" aria-label="Permalink to &quot;学完你能做什么&quot;">​</a></h2><ul><li>知道 0 Token/中断问题在代理里通常会先被“peek 预读”拦下来</li><li>能从 Proxy Monitor 里确认本次请求的账号与映射模型（<code>X-Account-Email</code> / <code>X-Mapped-Model</code>）</li><li>能通过日志判断是“上游流早夭”“退避重试”“轮换账号”还是“签名修复重试”</li><li>知道哪些情况该等代理自愈，哪些情况要手动介入</li></ul><h2 id="你现在的困境" tabindex="-1">你现在的困境 <a class="header-anchor" href="#你现在的困境" aria-label="Permalink to &quot;你现在的困境&quot;">​</a></h2><p>你可能看到这些“现象”，但不知道要从哪里下手：</p><ul><li>流式输出到一半断掉，客户端像“卡死”一样不再继续</li><li>200 OK，但 <code>usage.output_tokens=0</code> 或内容为空</li><li>400 错误里出现 <code>Invalid \\</code>signature`<code>、</code>Corrupted thought signature<code>、</code>must be `thinking`` 等</li></ul><p>这类问题大多不是“你请求写错了”，而是流式传输、上游限流/波动、或历史消息里携带的签名块触发了上游校验。Antigravity Tools 在代理层做了多道防线，你只需要按固定路径验证它到底卡在哪一步。</p><h2 id="什么是-0-token" tabindex="-1">什么是 0 Token？ <a class="header-anchor" href="#什么是-0-token" aria-label="Permalink to &quot;什么是 0 Token？&quot;">​</a></h2><p><strong>0 Token</strong>通常指一次请求最终返回的 <code>output_tokens=0</code>，并且看起来“没生成内容”。在 Antigravity Tools 里，它更常见的成因是“流式响应在真正输出前就结束/报错”，而不是模型真的生成了 0 个 token。代理会尝试用 peek 预读把这类空响应拦下来并触发重试。</p><h2 id="代理在背后做的三件事-先有心智模型" tabindex="-1">代理在背后做的三件事（先有心智模型） <a class="header-anchor" href="#代理在背后做的三件事-先有心智模型" aria-label="Permalink to &quot;代理在背后做的三件事（先有心智模型）&quot;">​</a></h2><h3 id="_1-非流式请求可能被自动转换为流式" tabindex="-1">1) 非流式请求可能被自动转换为流式 <a class="header-anchor" href="#_1-非流式请求可能被自动转换为流式" aria-label="Permalink to &quot;1) 非流式请求可能被自动转换为流式&quot;">​</a></h3><p><code>/v1/messages</code> 路径里，代理会在内部把“客户端非流式请求”转换为流式请求来请求上游，并在收到 SSE 后再收集成 JSON 返回（这样做的原因在日志里写明是“better quota”）。</p><p>源码证据：<code>src-tauri/src/proxy/handlers/claude.rs#L665-L913</code>。</p><h3 id="_2-peek-预读-先等到-第一块有效数据-再把流交给客户端" tabindex="-1">2) Peek 预读：先等到“第一块有效数据”再把流交给客户端 <a class="header-anchor" href="#_2-peek-预读-先等到-第一块有效数据-再把流交给客户端" aria-label="Permalink to &quot;2) Peek 预读：先等到“第一块有效数据”再把流交给客户端&quot;">​</a></h3><p>对 <code>/v1/messages</code> 的 SSE 输出，代理会先 <code>timeout + next()</code> 预读，跳过心跳/注释行（以 <code>:</code> 开头），直到拿到第一块“不是空、不是心跳”的数据再开始正式转发。如果 peek 阶段就报错/超时/流结束，会直接进入下一轮尝试（下一轮通常会触发账号轮换）。</p><p>源码证据：<code>src-tauri/src/proxy/handlers/claude.rs#L812-L926</code>；Gemini 原生流式也有类似 peek：<code>src-tauri/src/proxy/handlers/gemini.rs#L117-L149</code>。</p><h3 id="_3-统一退避重试-按状态码决定-要不要轮换账号" tabindex="-1">3) 统一退避重试 + 按状态码决定“要不要轮换账号” <a class="header-anchor" href="#_3-统一退避重试-按状态码决定-要不要轮换账号" aria-label="Permalink to &quot;3) 统一退避重试 + 按状态码决定“要不要轮换账号”&quot;">​</a></h3><p>代理对常见状态码做了明确的退避策略，并定义了哪些状态码会触发轮换账号。</p><p>源码证据：<code>src-tauri/src/proxy/handlers/claude.rs#L117-L236</code>。</p><h2 id="🎒-开始前的准备" tabindex="-1">🎒 开始前的准备 <a class="header-anchor" href="#🎒-开始前的准备" aria-label="Permalink to &quot;🎒 开始前的准备&quot;">​</a></h2><ul><li>你能打开 Proxy Monitor（见 <a href="./../../advanced/monitoring/">Proxy Monitor：请求日志、筛选、详情还原与导出</a>）</li><li>你知道日志在数据目录的 <code>logs/</code> 下（见 <a href="./../../start/first-run-data/">首次启动必懂：数据目录、日志、托盘与自动启动</a>）</li></ul><h2 id="跟我做" tabindex="-1">跟我做 <a class="header-anchor" href="#跟我做" aria-label="Permalink to &quot;跟我做&quot;">​</a></h2><h3 id="第-1-步-确认你调用的是哪条接口路径" tabindex="-1">第 1 步：确认你调用的是哪条接口路径 <a class="header-anchor" href="#第-1-步-确认你调用的是哪条接口路径" aria-label="Permalink to &quot;第 1 步：确认你调用的是哪条接口路径&quot;">​</a></h3><p><strong>为什么</strong><code>/v1/messages</code>（claude handler）和 Gemini 原生（gemini handler）的自愈细节不同，先确认路径能避免你在错的日志关键字上浪费时间。</p><p>打开 Proxy Monitor，找到那条失败的请求，先记下 Path：</p><ul><li><code>/v1/messages</code>：看 <code>src-tauri/src/proxy/handlers/claude.rs</code> 的逻辑</li><li><code>/v1beta/models/...:streamGenerateContent</code>：看 <code>src-tauri/src/proxy/handlers/gemini.rs</code> 的逻辑</li></ul><p><strong>你应该看到</strong>：请求记录里能看到 URL/方法/状态码（以及请求耗时）。</p><h3 id="第-2-步-从响应-header-里抓住-账号-映射模型" tabindex="-1">第 2 步：从响应 Header 里抓住“账号 + 映射模型” <a class="header-anchor" href="#第-2-步-从响应-header-里抓住-账号-映射模型" aria-label="Permalink to &quot;第 2 步：从响应 Header 里抓住“账号 + 映射模型”&quot;">​</a></h3><p><strong>为什么</strong> 同一个请求失败/成功，很多时候取决于“这次选到哪个账号”“被路由到哪个上游模型”。代理会把这两个信息写到响应头，先记下来，后面看日志能对上号。</p><p>在失败的那条请求里，找这些响应头：</p><ul><li><code>X-Account-Email</code></li><li><code>X-Mapped-Model</code></li></ul><p>这两项在 <code>/v1/messages</code> 和 Gemini handler 里都会设置（例如 <code>/v1/messages</code> 的 SSE 响应里：<code>src-tauri/src/proxy/handlers/claude.rs#L887-L896</code>；Gemini SSE：<code>src-tauri/src/proxy/handlers/gemini.rs#L235-L245</code>）。</p><p><strong>你应该看到</strong>：<code>X-Account-Email</code> 是邮箱，<code>X-Mapped-Model</code> 是实际请求的模型名。</p><h3 id="第-3-步-在-app-log-里判断是不是-peek-阶段就失败" tabindex="-1">第 3 步：在 app.log 里判断是不是“peek 阶段就失败” <a class="header-anchor" href="#第-3-步-在-app-log-里判断是不是-peek-阶段就失败" aria-label="Permalink to &quot;第 3 步：在 app.log 里判断是不是“peek 阶段就失败”&quot;">​</a></h3><p><strong>为什么</strong> peek 失败通常意味着“上游根本没开始吐有效数据”。这类问题最常见的处理方式是重试/轮换账号，你需要确认代理有没有触发。</p><p>先定位日志文件（日志目录来自数据目录的 <code>logs/</code>，并按天滚动写入 <code>app.log*</code>）。</p><div class="vp-code-group vp-adaptive-theme"><div class="tabs"><input type="radio" name="group-xeBQh" id="tab-bko6Pdo" checked><label data-title="macOS/Linux" for="tab-bko6Pdo">macOS/Linux</label><input type="radio" name="group-xeBQh" id="tab-puonh9s"><label data-title="Windows" for="tab-puonh9s">Windows</label></div><div class="blocks"><div class="language-bash vp-adaptive-theme active"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ls</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -lt</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$HOME</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/.antigravity_tools/logs&quot;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> head</span></span></code></pre></div><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Get-ChildItem</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> -</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Force (</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Join-Path</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> $HOME</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;.antigravity_tools\\logs&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">|</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> Sort-Object</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> LastWriteTime </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Descending </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">|</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> Select-Object</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> -</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">First </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">5</span></span></code></pre></div></div></div><p>然后在最新的 <code>app.log*</code> 里搜这些关键字：</p><ul><li><code>/v1/messages</code>（claude handler）：<code>Stream error during peek</code> / <code>Stream ended during peek</code> / <code>Timeout waiting for first data</code>（<code>src-tauri/src/proxy/handlers/claude.rs#L828-L864</code>）</li><li>Gemini 原生流式：<code>[Gemini] Empty first chunk received, retrying...</code> / <code>Stream error during peek</code> / <code>Stream ended immediately</code>（<code>src-tauri/src/proxy/handlers/gemini.rs#L117-L144</code>）</li></ul><p><strong>你应该看到</strong>：如果触发了 peek 重试，日志里会出现类似 “retrying...” 的告警，并且随后会进入下一轮 attempt（通常会带来账号轮换）。</p><h3 id="第-4-步-如果是-400-invalid-signature-确认代理是否做了-签名修复重试" tabindex="-1">第 4 步：如果是 400/Invalid <code>signature</code>，确认代理是否做了“签名修复重试” <a class="header-anchor" href="#第-4-步-如果是-400-invalid-signature-确认代理是否做了-签名修复重试" aria-label="Permalink to &quot;第 4 步：如果是 400/Invalid `signature`，确认代理是否做了“签名修复重试”&quot;">​</a></h3><p><strong>为什么</strong> 签名类错误经常来自历史消息里的 Thinking 块/签名块不符合上游要求。Antigravity Tools 会尝试“降级历史 thinking 块 + 注入修复提示词”再重试，你应该先让它自愈跑完。</p><p>你可以用 2 个信号判断它是否进入了修复逻辑：</p><ol><li>日志里出现 <code>Unexpected thinking signature error ... Retrying with all thinking blocks removed.</code>（<code>src-tauri/src/proxy/handlers/claude.rs#L999-L1025</code>）</li><li>随后会把历史 <code>Thinking</code> 块转换为 <code>Text</code>，并在最后一条 user message 追加修复提示词（<code>src-tauri/src/proxy/handlers/claude.rs#L1027-L1102</code>；Gemini handler 也会对 <code>contents[].parts</code> 追加同样的提示词：<code>src-tauri/src/proxy/handlers/gemini.rs#L300-L325</code>）</li></ol><p><strong>你应该看到</strong>：代理会在短延迟后自动重试（<code>FixedDelay</code>），并可能进入下一轮尝试。</p><h2 id="检查点-✅" tabindex="-1">检查点 ✅ <a class="header-anchor" href="#检查点-✅" aria-label="Permalink to &quot;检查点 ✅&quot;">​</a></h2><ul><li>[ ] 你能在 Proxy Monitor 里确认请求路径（<code>/v1/messages</code> 或 Gemini 原生）</li><li>[ ] 你能拿到本次请求的 <code>X-Account-Email</code> 与 <code>X-Mapped-Model</code></li><li>[ ] 你能在 <code>logs/app.log*</code> 里搜到 peek/重试相关关键字</li><li>[ ] 遇到 400 签名错误时，你能确认代理是否进入“修复提示词 + 清理 thinking 块”的重试逻辑</li></ul><h2 id="踩坑提醒" tabindex="-1">踩坑提醒 <a class="header-anchor" href="#踩坑提醒" aria-label="Permalink to &quot;踩坑提醒&quot;">​</a></h2><table tabindex="0"><thead><tr><th>场景</th><th>你可能会怎么做（❌）</th><th>推荐做法（✓）</th></tr></thead><tbody><tr><td>看到 0 Token 就立刻手动重试很多次</td><td>一直按客户端重试按钮，完全不看日志</td><td>先看一次 Proxy Monitor + app.log，确认是否是 peek 阶段早夭（会自动重试/轮换）</td></tr><tr><td>遇到 <code>Invalid \\</code>signature`` 就直接清空数据目录</td><td>把 <code>.antigravity_tools</code> 整个删掉，账号/统计全没了</td><td>先让代理执行一次“签名修复重试”；只有在日志明确提示不可恢复时，再考虑手动介入</td></tr><tr><td>把“服务端波动”当成“账号坏了”</td><td>400/503/529 一律轮换账号</td><td>轮换是否有效取决于状态码；代理本身有 <code>should_rotate_account(...)</code> 规则（<code>src-tauri/src/proxy/handlers/claude.rs#L226-L236</code>）</td></tr></tbody></table><h2 id="本课小结" tabindex="-1">本课小结 <a class="header-anchor" href="#本课小结" aria-label="Permalink to &quot;本课小结&quot;">​</a></h2><ul><li>0 Token/流式中断在代理里通常先经过 peek 预读；peek 阶段失败会触发重试并进入下一轮 attempt</li><li><code>/v1/messages</code> 可能会把非流式请求内部转换为流式再收集回 JSON，这会影响你理解“为什么看起来像流式问题”</li><li>签名失效类 400 错误，代理会尝试“修复提示词 + 清理 thinking 块”再重试，你优先验证这条自愈路径是否走通</li></ul><h2 id="下一课预告" tabindex="-1">下一课预告 <a class="header-anchor" href="#下一课预告" aria-label="Permalink to &quot;下一课预告&quot;">​</a></h2><blockquote><p>下一课我们学习 <strong><a href="./../../appendix/endpoints/">端点速查表</a></strong>。</p></blockquote><hr><h2 id="附录-源码参考" tabindex="-1">附录：源码参考 <a class="header-anchor" href="#附录-源码参考" aria-label="Permalink to &quot;附录：源码参考&quot;">​</a></h2><details><summary><strong>点击展开查看源码位置</strong></summary><blockquote><p>更新时间：2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>功能</th><th>文件路径</th><th>行号</th></tr></thead><tbody><tr><td>Claude handler：退避重试策略 + 轮换规则</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/handlers/claude.rs#L117-L236" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/handlers/claude.rs</code></a></td><td>117-236</td></tr><tr><td>Claude handler：内部把非流式转换为流式（better quota）</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/handlers/claude.rs#L665-L776" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/handlers/claude.rs</code></a></td><td>665-776</td></tr><tr><td>Claude handler：peek 预读（跳过心跳/注释，避免空流）</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/handlers/claude.rs#L812-L926" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/handlers/claude.rs</code></a></td><td>812-926</td></tr><tr><td>Claude handler：400 签名/块顺序错误的修复重试</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/handlers/claude.rs#L999-L1102" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/handlers/claude.rs</code></a></td><td>999-1102</td></tr><tr><td>Gemini handler：peek 预读（防止空流 200 OK）</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/handlers/gemini.rs#L117-L149" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/handlers/gemini.rs</code></a></td><td>117-149</td></tr><tr><td>Gemini handler：400 签名错误的修复提示词注入</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/handlers/gemini.rs#L300-L325" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/handlers/gemini.rs</code></a></td><td>300-325</td></tr><tr><td>签名缓存（三层：tool/family/session，含 TTL/最小长度）</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/signature_cache.rs#L5-L207" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/signature_cache.rs</code></a></td><td>5-207</td></tr><tr><td>Claude SSE 转换：捕获签名并写入签名缓存</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/mappers/claude/streaming.rs#L639-L787" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/mappers/claude/streaming.rs</code></a></td><td>639-787</td></tr></tbody></table><p><strong>关键常量</strong>：</p><ul><li><code>MAX_RETRY_ATTEMPTS = 3</code>：最大重试次数（<code>src-tauri/src/proxy/handlers/claude.rs#L27</code>）</li><li><code>SIGNATURE_TTL = 2 * 60 * 60</code> 秒：签名缓存 TTL（<code>src-tauri/src/proxy/signature_cache.rs#L6</code>）</li><li><code>MIN_SIGNATURE_LENGTH = 50</code>：签名最小长度（<code>src-tauri/src/proxy/signature_cache.rs#L7</code>）</li></ul><p><strong>关键函数</strong>：</p><ul><li><code>determine_retry_strategy(...)</code>：按状态码选择退避策略（<code>src-tauri/src/proxy/handlers/claude.rs#L117-L167</code>）</li><li><code>should_rotate_account(...)</code>：按状态码决定是否轮换账号（<code>src-tauri/src/proxy/handlers/claude.rs#L226-L236</code>）</li><li><code>SignatureCache::cache_session_signature(...)</code>：缓存会话签名（<code>src-tauri/src/proxy/signature_cache.rs#L149-L188</code>）</li></ul></details>',57)])])}const g=a(o,[["render",s]]);export{u as __pageData,g as default};
